<body>
    <div class="container">
        <h1 class="title">Falling Sand Sandbox</h1>
        <div class="canvas-wrapper">
            <canvas id="sand"></canvas>
        </div>
        <div class="controls">
            <button id="mat-sand" class="mat-btn selected">Sand</button>
            <button id="mat-water" class="mat-btn">Water</button>
            <button id="mat-wall" class="mat-btn">Wall</button>
            <button id="mat-acid" class="mat-btn">Acid</button>
            <button id="mat-empty" class="mat-btn">Eraser</button>
            <button id="clear">Clear</button>
        </div>
        <p class="hint">Click &amp; drag on the canvas to paint · Watch the simulation run</p>
    </div>

    <script>
        (function() {
            // ─────────────────────────────────────
            // Configuration
            // ─────────────────────────────────────
            const CELL_SIZE = 5;
            const GRID_W = 100;
            const GRID_H = 80;
            const CANVAS_W = GRID_W * CELL_SIZE; // 500
            const CANVAS_H = GRID_H * CELL_SIZE; // 400
            const BRUSH_RADIUS = 2; // cells

            // Material type codes
            const EMPTY = 0;
            const SAND = 1;
            const WATER = 2;
            const WALL = 3;
            const ACID = 4;

            // Material name mapping
            const CODE_TO_NAME = ['empty', 'sand', 'water', 'wall', 'acid'];
            const NAME_TO_CODE = {
                'empty': EMPTY,
                'sand': SAND,
                'water': WATER,
                'wall': WALL,
                'acid': ACID
            };

            // Colors for rendering
            const COLORS = [
                '#1e1e30', // empty - dark canvas bg
                '#e8c547', // sand - golden yellow
                '#4a9eeb', // water - blue
                '#7a7a8a', // wall - medium gray
                '#4de64d', // acid - bright green
            ];

            // Slightly varied sand colors for organic look
            const SAND_VARIANTS = [
                '#e8c547', '#e6c040', '#eacb50', '#e4bd3d', '#eccf55',
                '#e7c445', '#e9c84a', '#e5bf42', '#ebcc52', '#e3bb3a'
            ];
            const WATER_VARIANTS = [
                '#4a9eeb', '#4899e5', '#4ca3f0', '#4794e0', '#4da8f2',
                '#499ce8', '#4ba0ed', '#4692de', '#4eaaf4', '#4897e3'
            ];
            const ACID_VARIANTS = [
                '#4de64d', '#4ae04a', '#50ec50', '#48d848', '#52f052',
                '#4ce44c', '#4fea4f', '#47d647', '#51ee51', '#49da49'
            ];

            // ─────────────────────────────────────
            // DOM elements
            // ─────────────────────────────────────
            const canvas = document.getElementById('sand');
            const ctx = canvas.getContext('2d');
            canvas.width = CANVAS_W;
            canvas.height = CANVAS_H;
            canvas.style.width = CANVAS_W + 'px';
            canvas.style.height = CANVAS_H + 'px';

            const btnSand = document.getElementById('mat-sand');
            const btnWater = document.getElementById('mat-water');
            const btnWall = document.getElementById('mat-wall');
            const btnAcid = document.getElementById('mat-acid');
            const btnEmpty = document.getElementById('mat-empty');
            const btnClear = document.getElementById('clear');

            const materialButtons = [btnSand, btnWater, btnWall, btnAcid, btnEmpty];
            const materialMap = {
                'mat-sand': SAND,
                'mat-water': WATER,
                'mat-wall': WALL,
                'mat-acid': ACID,
                'mat-empty': EMPTY
            };

            // ─────────────────────────────────────
            // State
            // ─────────────────────────────────────
            let selectedMaterial = SAND;
            const grid = new Uint8Array(GRID_W * GRID_H); // all zeros (empty)
            const moved = new Uint8Array(GRID_W * GRID_H); // tracking array

            // Mouse state
            let mouseDown = false;
            let mouseCellX = -1;
            let mouseCellY = -1;

            // ─────────────────────────────────────
            // Grid helpers
            // ─────────────────────────────────────
            function idx(x, y) {
                return y * GRID_W + x;
            }

            function inBounds(x, y) {
                return x >= 0 && x < GRID_W && y >= 0 && y < GRID_H;
            }

            function getCell(x, y) {
                if (!inBounds(x, y)) return WALL; // boundaries act as walls
                return grid[idx(x, y)];
            }

            function setCell(x, y, mat) {
                if (inBounds(x, y)) {
                    grid[idx(x, y)] = mat;
                }
            }

            function setCellDirect(idx, mat) {
                grid[idx] = mat;
            }

            function getCellDirect(i) {
                return grid[i];
            }

            // ─────────────────────────────────────
            // Shuffle helper (Fisher-Yates)
            // ─────────────────────────────────────
            function shuffle(arr) {
                for (let i = arr.length - 1; i > 0; i--) {
                    const j = Math.floor(Math.random() * (i + 1));
                    [arr[i], arr[j]] = [arr[j], arr[i]];
                }
                return arr;
            }

            // ─────────────────────────────────────
            // Simulation step
            // ─────────────────────────────────────
            function simulateStep() {
                // Reset moved array
                moved.fill(0);

                // Process rows bottom-up
                for (let y = GRID_H - 1; y >= 0; y--) {
                    // Create shuffled column order for this row
                    const cols = shuffle([...Array(GRID_W).keys()]);

                    for (const x of cols) {
                        const i = idx(x, y);
                        if (moved[i] === 1) continue;

                        const mat = grid[i];
                        if (mat === EMPTY || mat === WALL) continue;

                        if (mat === SAND) {
                            processSand(x, y, i);
                        } else if (mat === WATER) {
                            processWater(x, y, i);
                        } else if (mat === ACID) {
                            processAcid(x, y, i);
                        }
                    }
                }
            }

            function processSand(x, y, i) {
                // Try to fall straight down
                const below = getCell(x, y + 1);

                if (below === EMPTY) {
                    // Fall into empty
                    moveParticle(i, x, y, x, y + 1);
                    return;
                }

                if (below === WATER || below === ACID) {
                    // Swap: sand sinks through water/acid
                    swapParticles(i, x, y, x, y + 1);
                    return;
                }

                // Blocked below — try diagonals
                const goLeftFirst = Math.random() < 0.5;
                const dirs = goLeftFirst ? [-1, 1] : [1, -1];

                for (const dx of dirs) {
                    const nx = x + dx;
                    const ny = y + 1;
                    const diag = getCell(nx, ny);

                    if (diag === EMPTY) {
                        moveParticle(i, x, y, nx, ny);
                        return;
                    }
                    if (diag === WATER || diag === ACID) {
                        swapParticles(i, x, y, nx, ny);
                        return;
                    }
                }
                // Sand rests
            }

            function processWater(x, y, i) {
                // Try to fall straight down
                const below = getCell(x, y + 1);

                if (below === EMPTY) {
                    moveParticle(i, x, y, x, y + 1);
                    return;
                }

                // Blocked — spread horizontally into empty cells
                const goLeftFirst = Math.random() < 0.5;
                const dirs = goLeftFirst ? [-1, 1] : [1, -1];

                for (const dx of dirs) {
                    const nx = x + dx;
                    const side = getCell(nx, y);
                    if (side === EMPTY) {
                        moveParticle(i, x, y, nx, y);
                        return;
                    }
                }
                // Water stays
            }

            function processAcid(x, y, i) {
                // First: dissolve adjacent sand/wall (below, left, right)
                const dissolveTargets = [
                    [x, y + 1], // below
                    [x - 1, y], // left
                    [x + 1, y], // right
                ];

                for (const [tx, ty] of dissolveTargets) {
                    if (inBounds(tx, ty)) {
                        const tmat = getCell(tx, ty);
                        if (tmat === SAND || tmat === WALL) {
                            // Dissolve it
                            setCell(tx, ty, EMPTY);
                            // Mark as moved so it doesn't get processed this step
                            if (inBounds(tx, ty)) {
                                moved[idx(tx, ty)] = 1;
                            }
                        }
                    }
                }

                // Now move like water
                const below = getCell(x, y + 1);
                if (below === EMPTY) {
                    moveParticle(i, x, y, x, y + 1);
                    return;
                }

                // Blocked — spread horizontally into empty cells
                const goLeftFirst = Math.random() < 0.5;
                const dirs = goLeftFirst ? [-1, 1] : [1, -1];

                for (const dx of dirs) {
                    const nx = x + dx;
                    const side = getCell(nx, y);
                    if (side === EMPTY) {
                        moveParticle(i, x, y, nx, y);
                        return;
                    }
                }
                // Acid stays
            }

            function moveParticle(srcIdx, sx, sy, dx, dy) {
                const di = idx(dx, dy);
                const mat = grid[srcIdx];
                grid[srcIdx] = EMPTY;
                grid[di] = mat;
                moved[srcIdx] = 1;
                moved[di] = 1;
            }

            function swapParticles(srcIdx, sx, sy, dx, dy) {
                const di = idx(dx, dy);
                const srcMat = grid[srcIdx];
                const dstMat = grid[di];
                grid[srcIdx] = dstMat;
                grid[di] = srcMat;
                moved[srcIdx] = 1;
                moved[di] = 1;
            }

            // ─────────────────────────────────────
            // Rendering
            // ─────────────────────────────────────
            function render() {
                // Clear canvas with background color
                ctx.fillStyle = COLORS[EMPTY];
                ctx.fillRect(0, 0, CANVAS_W, CANVAS_H);

                // Draw each non-empty cell
                for (let y = 0; y < GRID_H; y++) {
                    for (let x = 0; x < GRID_W; x++) {
                        const mat = grid[idx(x, y)];
                        if (mat === EMPTY) continue;

                        let color;
                        if (mat === SAND) {
                            // Use variant for organic look
                            const variantIdx = (x * 7 + y * 13) % SAND_VARIANTS.length;
                            color = SAND_VARIANTS[variantIdx];
                        } else if (mat === WATER) {
                            const variantIdx = (x * 11 + y * 5) % WATER_VARIANTS.length;
                            color = WATER_VARIANTS[variantIdx];
                        } else if (mat === ACID) {
                            const variantIdx = (x * 3 + y * 17) % ACID_VARIANTS.length;
                            color = ACID_VARIANTS[variantIdx];
                        } else {
                            color = COLORS[mat];
                        }

                        ctx.fillStyle = color;
                        ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, CELL_SIZE);

                        // Subtle highlight on top edge for depth (sand and wall)
                        if (mat === SAND || mat === WALL) {
                            ctx.fillStyle = 'rgba(255,255,255,0.12)';
                            ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, 1);
                        }
                        if (mat === WATER || mat === ACID) {
                            ctx.fillStyle = 'rgba(255,255,255,0.18)';
                            ctx.fillRect(x * CELL_SIZE, y * CELL_SIZE, CELL_SIZE, 1);
                        }
                    }
                }
            }

            // ─────────────────────────────────────
            // Painting
            // ─────────────────────────────────────
            function paintAt(cellX, cellY) {
                const mat = selectedMaterial;
                const radius = BRUSH_RADIUS;
                const r2 = radius * radius;

                for (let dy = -radius; dy <= radius; dy++) {
                    for (let dx = -radius; dx <= radius; dx++) {
                        if (dx * dx + dy * dy <= r2) {
                            const px = cellX + dx;
                            const py = cellY + dy;
                            if (inBounds(px, py)) {
                                setCell(px, py, mat);
                            }
                        }
                    }
                }
            }

            function getCanvasCellCoords(e) {
                const rect = canvas.getBoundingClientRect();
                const scaleX = CANVAS_W / rect.width;
                const scaleY = CANVAS_H / rect.height;
                const mx = (e.clientX - rect.left) * scaleX;
                const my = (e.clientY - rect.top) * scaleY;
                const cx = Math.floor(mx / CELL_SIZE);
                const cy = Math.floor(my / CELL_SIZE);
                return {
                    x: Math.max(0, Math.min(GRID_W - 1, cx)),
                    y: Math.max(0, Math.min(GRID_H - 1, cy))
                };
            }

            // ─────────────────────────────────────
            // Event handlers
            // ─────────────────────────────────────
            canvas.addEventListener('mousedown', (e) => {
                if (e.button === 0) {
                    mouseDown = true;
                    const coords = getCanvasCellCoords(e);
                    mouseCellX = coords.x;
                    mouseCellY = coords.y;
                    paintAt(mouseCellX, mouseCellY);
                    e.preventDefault();
                }
            });

            canvas.addEventListener('mousemove', (e) => {
                const coords = getCanvasCellCoords(e);
                mouseCellX = coords.x;
                mouseCellY = coords.y;
                if (mouseDown) {
                    paintAt(mouseCellX, mouseCellY);
                }
            });

            window.addEventListener('mouseup', () => {
                mouseDown = false;
            });

            canvas.addEventListener('mouseleave', () => {
                mouseDown = false;
            });

            // Touch support
            canvas.addEventListener('touchstart', (e) => {
                if (e.touches.length === 1) {
                    mouseDown = true;
                    const coords = getCanvasCellCoords(e.touches[0]);
                    mouseCellX = coords.x;
                    mouseCellY = coords.y;
                    paintAt(mouseCellX, mouseCellY);
                    e.preventDefault();
                }
            }, { passive: false });

            canvas.addEventListener('touchmove', (e) => {
                if (mouseDown && e.touches.length === 1) {
                    const coords = getCanvasCellCoords(e.touches[0]);
                    mouseCellX = coords.x;
                    mouseCellY = coords.y;
                    paintAt(mouseCellX, mouseCellY);
                    e.preventDefault();
                }
            }, { passive: false });

            canvas.addEventListener('touchend', () => {
                mouseDown = false;
            });
            canvas.addEventListener('touchcancel', () => {
                mouseDown = false;
            });

            // Button handlers
            function updateSelectedButton() {
                materialButtons.forEach(btn => btn.classList.remove('selected'));
                const name = CODE_TO_NAME[selectedMaterial];
                const btnId = 'mat-' + name;
                const btn = document.getElementById(btnId);
                if (btn) btn.classList.add('selected');
            }

            btnSand.addEventListener('click', () => {
                selectedMaterial = SAND;
                updateSelectedButton();
            });
            btnWater.addEventListener('click', () => {
                selectedMaterial = WATER;
                updateSelectedButton();
            });
            btnWall.addEventListener('click', () => {
                selectedMaterial = WALL;
                updateSelectedButton();
            });
            btnAcid.addEventListener('click', () => {
                selectedMaterial = ACID;
                updateSelectedButton();
            });
            btnEmpty.addEventListener('click', () => {
                selectedMaterial = EMPTY;
                updateSelectedButton();
            });

            btnClear.addEventListener('click', () => {
                clearGrid();
            });

            function clearGrid() {
                grid.fill(EMPTY);
                moved.fill(0);
            }

            // ─────────────────────────────────────
            // Programmatic API (exposed on window.sim)
            // ─────────────────────────────────────
            window.sim = {
                w: GRID_W,
                h: GRID_H,

                tick(n) {
                    const steps = Math.max(0, Math.floor(n));
                    for (let s = 0; s < steps; s++) {
                        simulateStep();
                    }
                },

                get(x, y) {
                    if (!inBounds(x, y)) return 'wall';
                    return CODE_TO_NAME[grid[idx(x, y)]];
                },

                set(x, y, material) {
                    if (!inBounds(x, y)) return;
                    const code = NAME_TO_CODE[material];
                    if (code !== undefined) {
                        grid[idx(x, y)] = code;
                    }
                },

                clear() {
                    clearGrid();
                },
            };

            // ─────────────────────────────────────
            // Animation loop
            // ─────────────────────────────────────
            function animationFrame() {
                // Paint continuously while mouse is held down
                if (mouseDown && inBounds(mouseCellX, mouseCellY)) {
                    paintAt(mouseCellX, mouseCellY);
                }

                // Advance simulation
                simulateStep();

                // Render
                render();

                requestAnimationFrame(animationFrame);
            }

            // ─────────────────────────────────────
            // Initial render and start
            // ─────────────────────────────────────
            updateSelectedButton();
            render();
            requestAnimationFrame(animationFrame);

            console.log('Falling Sand Sandbox ready.');
            console.log('Grid: ' + GRID_W + '×' + GRID_H + ' cells (' + CANVAS_W + '×' + CANVAS_H + ' px)');
            console.log('API available at window.sim — try sim.tick(10), sim.set(50,10,"sand"), sim.get(50,10)');
        })();
    </script>
</body>
</html>
